import React, { useState } from 'react';
import Header from './components/Header.jsx';
import BookingPage from './components/BookingPage.jsx';
import ConfirmationPage from './components/ConfirmationPage.jsx';
import AdminLogin from './components/admin/AdminLogin.jsx';
import AdminDashboard from './components/admin/AdminDashboard.jsx';
import styles from './styles/App.module.css';

const getRoute = () => window.location.hash === '#/admin' ? 'admin' : 'guest';

const App = () => {
  const [route,       setRoute]       = useState(getRoute);
  const [bookingData, setBookingData] = useState(null);
  const [step,        setStep]        = useState('booking');
  const [adminUser,   setAdminUser]   = useState(null);

  React.useEffect(() => {
    const onHash = () => setRoute(getRoute());
    window.addEventListener('hashchange', onHash);
    return () => window.removeEventListener('hashchange', onHash);
  }, []);

  if (route === 'admin') {
    if (!adminUser) return <AdminLogin onLogin={setAdminUser} />;
    return <AdminDashboard admin={adminUser}
      onLogout={() => { setAdminUser(null); window.location.hash = ''; }} />;
  }

  return (
    <div className={styles.app}>
      <Header />
      <main className={styles.main}>
        {step === 'booking' && (
          <BookingPage onConfirm={(data) => { setBookingData(data); setStep('confirmed'); }} />
        )}
        {step === 'confirmed' && (
          <ConfirmationPage data={bookingData}
            onNewBooking={() => { setBookingData(null); setStep('booking'); }} />
        )}
      </main>
      <footer className={styles.footer}>
        <div className={styles.footerInner}>
          <span className={styles.footerLogo}>水屋</span>
          <p>© 2026 Mizuya Exclusive Resort · Bukidnon, Philippines</p>
          <p>Check-in: 2:00 PM · Check-out: 12:00 NN</p>
        </div>
      </footer>
    </div>
  );
};

export default App;
